import { useState } from 'react'
import { useQuery } from '@tanstack/react-query'
import { Play, Download, TrendingUp, TrendingDown, BarChart3, Target, Percent, DollarSign, Activity } from 'lucide-react'
import { cn, formatCurrency } from '@/lib/utils'
import { backtestApi } from '@/lib/api'
import { KPICard } from '@/components/ui/KPICard'
import { Skeleton } from '@/components/ui/Skeleton'
import { EmptyState } from '@/components/ui/EmptyState'
import { SectionCard } from '@/components/ui/SectionCard'
import { PageHeader } from '@/components/ui/PageHeader'

const METRICS = [
  { label: '总收益率', key: 'total_return', icon: TrendingUp, format: (v: number) => `${v >= 0 ? '+' : ''}${v.toFixed(2)}%`, color: 'green' as const },
  { label: '年化收益', key: 'annualized_return', icon: BarChart3, format: (v: number) => `${v >= 0 ? '+' : ''}${v.toFixed(2)}%`, color: 'green' as const },
  { label: '最大回撤', key: 'max_drawdown', icon: TrendingDown, format: (v: number) => `${v.toFixed(2)}%`, color: 'red' as const },
  { label: '夏普比率', key: 'sharpe', icon: Target, format: (v: number) => v.toFixed(2), color: 'gold' as const },
  { label: '胜率', key: 'win_rate', icon: Percent, format: (v: number) => `${v.toFixed(1)}%`, color: 'green' as const },
  { label: '盈亏比', key: 'profit_factor', icon: DollarSign, format: (v: number) => `${v.toFixed(2)}:1`, color: 'gold' as const },
]

export function Backtest() {
  const [running, setRunning] = useState(false)
  const [progress, setProgress] = useState(0)
  const [result, setResult] = useState<any | null>(null)

  const handleRun = () => {
    setRunning(true)
    setProgress(0)
    const iv = setInterval(() => {
      setProgress((p) => {
        if (p >= 100) {
          clearInterval(iv)
          setRunning(false)
          setResult({
            total_return: 124.5,
            annualized_return: 456.2,
            max_drawdown: -18.3,
            sharpe: 2.34,
            win_rate: 62.4,
            profit_factor: 2.41,
            total_trades: 156,
            avg_trade: 12.5,
            best_trade: 85.3,
            worst_trade: -32.1,
            avg_duration: '2.4h',
          })
          return 100
        }
        return p + 2
      })
    }, 120)
  }

  return (
    <div className="h-full overflow-y-auto">
      <div className="max-w-6xl mx-auto p-5 space-y-5">
        <PageHeader
          title="回测验证"
          subtitle="使用历史数据验证策略表现"
          actions={
            <>
              <button className="px-3 py-2 rounded-lg bg-[#1c1c1c] text-sm text-white hover:bg-[#262626] transition-colors flex items-center gap-1.5">
                <Download className="w-3.5 h-3.5" />导出
              </button>
              <button
                onClick={handleRun}
                disabled={running}
                className={cn('px-4 py-2 rounded-lg text-sm font-medium transition-opacity flex items-center gap-1.5', running ? 'bg-quant-gold/50 cursor-not-allowed' : 'bg-quant-gold hover:opacity-90 text-white')}
              >
                <Play className="w-3.5 h-3.5" /> {running ? '运行中...' : '开始回测'}
              </button>
            </>
          }
        />

        {running && (
          <SectionCard className="p-5">
            <div className="flex justify-between text-xs mb-2">
              <span className="text-[#aaaaaa]">回测进度</span>
              <span className="font-mono text-white">{progress}%</span>
            </div>
            <div className="h-2 bg-[#1c1c1c] rounded-full overflow-hidden">
              <div className="h-full bg-quant-gold rounded-full transition-all duration-200" style={{ width: `${progress}%` }} />
            </div>
          </SectionCard>
        )}

        {!running && result && (
          <>
            <div className="grid grid-cols-2 md:grid-cols-3 xl:grid-cols-6 gap-4">
              {METRICS.map((m) => (
                <KPICard
                  key={m.key}
                  icon={<m.icon className="w-4 h-4 text-[#aaaaaa]" />}
                  label={m.label}
                  value={m.format(result[m.key])}
                  trend={m.color === 'green' ? 'up' : m.color === 'red' ? 'down' : 'neutral'}
                />
              ))}
            </div>

            <SectionCard title="详细统计">
              <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                {[
                  { label: '总交易数', value: result.total_trades },
                  { label: '平均收益', value: `+$${result.avg_trade}` },
                  { label: '最佳交易', value: `+$${result.best_trade}` },
                  { label: '最差交易', value: `-$${Math.abs(result.worst_trade)}` },
                  { label: '平均持仓', value: result.avg_duration },
                  { label: '盈利交易', value: '97' },
                  { label: '亏损交易', value: '59' },
                  { label: '连续盈利', value: '8' },
                ].map((s) => (
                  <div key={s.label} className="bg-[#0a0a0a] rounded-lg p-4 border border-[#1c1c1c]">
                    <div className="text-[11px] text-[#555555] mb-1">{s.label}</div>
                    <div className="text-lg font-mono font-semibold text-white">{s.value}</div>
                  </div>
                ))}
              </div>
            </SectionCard>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-5">
              <SectionCard title="权益曲线">
                <div className="h-64 bg-[#0a0a0a] rounded-lg flex items-center justify-center text-[#444444] text-sm">权益曲线图表区域</div>
              </SectionCard>
              <SectionCard title="月度收益分布">
                <div className="h-64 bg-[#0a0a0a] rounded-lg flex items-center justify-center text-[#444444] text-sm">月度收益柱状图区域</div>
              </SectionCard>
            </div>

            <SectionCard
              title="交易记录"
              headerAction={
                <button className="flex items-center gap-1 text-xs text-quant-gold hover:opacity-80">
                  <Download className="w-3.5 h-3.5" /> 导出 CSV
                </button>
              }
            >
              <div className="overflow-x-auto">
                <table className="w-full text-xs">
                  <thead>
                    <tr className="text-left text-[#555555] border-b border-[#1c1c1c]">
                      {['时间', '方向', '价格', '数量', '盈亏', '持仓时间'].map((h) => (
                        <th key={h} className="pb-3 font-medium px-2">{h}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {[1, 2, 3, 4, 5].map((i) => (
                      <tr key={i} className="border-b border-[#1c1c1c]/50 hover:bg-white/[0.02]">
                        <td className="py-3 px-2 text-[#555555]">2024-01-{10 + i} 14:30</td>
                        <td className="py-3 px-2">
                          <span className={cn('px-1.5 py-0.5 rounded text-[10px]', i % 2 === 0 ? 'bg-quant-green/10 text-quant-green' : 'bg-quant-red/10 text-quant-red')}>
                            {i % 2 === 0 ? '买入' : '卖出'}
                          </span>
                        </td>
                        <td className="py-3 px-2 font-mono">$42,3{i}5.00</td>
                        <td className="py-3 px-2 font-mono">0.{i}500 BTC</td>
                        <td className={cn('py-3 px-2 font-mono', i % 2 === 0 ? 'text-quant-green' : 'text-quant-red')}>
                          {i % 2 === 0 ? '+' : '-'}${(i * 123).toFixed(2)}
                        </td>
                        <td className="py-3 px-2 text-[#555555]">{i}.4h</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </SectionCard>
          </>
        )}

        {!running && !result && (
          <EmptyState
            icon={<Activity className="h-6 w-6" />}
            title="开始回测"
            description="配置策略参数并点击「开始回测」查看历史表现"
            actionLabel="开始回测"
            onAction={handleRun}
          />
        )}
      </div>
    </div>
  )
}
