function AnalysisResultView({
  result,
  loading,
  error,
  onRetry,
}: {
  result: AnalysisResult | null
  loading: boolean
  error: string | null
  onRetry: () => void
}) {
  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center h-full min-h-[300px] gap-4">
        <Loader2 className="w-8 h-8 text-quant-gold animate-spin" />
        <div className="text-sm text-muted-foreground">AI 正在分析中，请稍候...</div>
        <div className="w-48 h-1.5 bg-quant-border rounded-full overflow-hidden">
          <div className="h-full bg-quant-gold animate-progress rounded-full" />
        </div>
      </div>
    )
  }

  if (error) {
    return (
      <div className="flex flex-col items-center justify-center h-full min-h-[300px] gap-3">
        <div className="text-sm text-quant-red">{error}</div>
        <button
          onClick={onRetry}
          className="px-4 py-2 rounded-lg bg-quant-gold text-white text-xs font-medium hover:opacity-90 transition-opacity"
        >
          重试
        </button>
      </div>
    )
  }

  if (!result) return null

  const plan = result.trading_plan || {}
  const scores = result.scores || {}

  return (
    <div className="space-y-4">
      {/* Decision header */}
      <div className="flex items-center gap-3">
        <div
          className={cn(
            'px-3 py-1 rounded-lg text-xs font-bold',
            result.decision === 'BUY'
              ? 'bg-quant-green/10 text-quant-green'
              : result.decision === 'SELL'
              ? 'bg-quant-red/10 text-quant-red'
              : 'bg-quant-blue/10 text-quant-blue'
          )}
        >
          {result.decision}
        </div>
        <div className="text-sm text-muted-foreground">
          置信度 <span className="font-mono font-bold text-foreground">{result.confidence}%</span>
        </div>
      </div>

      {/* Summary */}
      <div className="bg-quant-card border border-quant-border rounded-xl p-4">
        <div className="text-xs font-bold text-foreground mb-2">分析摘要</div>
        <p className="text-xs text-muted-foreground leading-relaxed">{result.summary}</p>
      </div>

      {/* Trading plan */}
      <div className="bg-quant-card border border-quant-border rounded-xl p-4">
        <div className="text-xs font-bold text-foreground mb-3">交易计划</div>
        <div className="grid grid-cols-3 gap-3">
          {[
            { label: '入场价', value: plan.entry_price },
            { label: '止损', value: plan.stop_loss },
            { label: '止盈', value: plan.take_profit },
          ].map((item) => (
            <div key={item.label} className="text-center p-2 bg-quant-bg-secondary rounded-lg">
              <div className="text-[10px] text-muted-foreground mb-1">{item.label}</div>
              <div className="text-sm font-mono font-bold text-foreground">{item.value ? formatPrice(item.value) : '--'}</div>
            </div>
          ))}
        </div>
      </div>

      {/* Scores */}
      {Object.keys(scores).length > 0 && (
        <div className="bg-quant-card border border-quant-border rounded-xl p-4">
          <div className="text-xs font-bold text-foreground mb-3">评分维度</div>
          <div className="grid grid-cols-2 gap-2">
            {Object.entries(scores).map(([k, v]) => (
              <div key={k} className="flex items-center justify-between p-2 bg-quant-bg-secondary rounded-lg">
                <span className="text-[10px] text-muted-foreground capitalize">{k}</span>
                <span className="text-xs font-mono font-bold text-foreground">{formatNum(v as number)}</span>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Reasons */}
      {result.reasons && result.reasons.length > 0 && (
        <div className="bg-quant-card border border-quant-border rounded-xl p-4">
          <div className="text-xs font-bold text-foreground mb-2">核心逻辑</div>
          <ul className="space-y-1.5">
            {result.reasons.map((r, i) => (
              <li key={i} className="text-xs text-muted-foreground flex items-start gap-2">
                <span className="w-1 h-1 rounded-full bg-quant-gold mt-1.5 shrink-0" />
                {r}
              </li>
            ))}
          </ul>
        </div>
      )}

      {/* Risks */}
      {result.risks && result.risks.length > 0 && (
        <div className="bg-quant-card border border-quant-border rounded-xl p-4">
          <div className="text-xs font-bold text-foreground mb-2">风险提示</div>
          <ul className="space-y-1.5">
            {result.risks.map((r, i) => (
              <li key={i} className="text-xs text-muted-foreground flex items-start gap-2">
                <span className="w-1 h-1 rounded-full bg-quant-red mt-1.5 shrink-0" />
                {r}
              </li>
            ))}
          </ul>
        </div>
      )}
    </div>
  )
}

