import { Link, useLocation } from 'react-router-dom'
import { cn } from '@/lib/utils'
import { useAppStore } from '@/stores/appStore'
import {
  BarChart3,
  LineChart,
  Wallet,
  Cpu,
  FlaskConical,
  Bot,
  Settings,
  ChevronLeft,
  ChevronRight,
} from 'lucide-react'

const navItems = [
  { path: '/dashboard', label: '仪表盘', icon: BarChart3 },
  { path: '/trading', label: '交易', icon: LineChart },
  { path: '/strategy', label: '策略', icon: Wallet },
  { path: '/ai', label: 'AI研究', icon: Cpu },
  { path: '/backtest', label: '回测', icon: FlaskConical },
  { path: '/bots', label: '机器人', icon: Bot },
]

export function Sidebar() {
  const location = useLocation()
  const { sidebarCollapsed, toggleSidebar } = useAppStore()

  return (
    <aside
      className={cn(
        'flex flex-col bg-quant-bg border-r border-quant-border shrink-0 transition-all duration-200',
        sidebarCollapsed ? 'w-16' : 'w-56'
      )}
    >
      {/* Logo */}
      <div className="h-14 flex items-center px-4 border-b border-quant-border">
        <Link to="/" className="flex items-center gap-2 text-quant-gold font-bold tracking-tight">
          <span className="w-7 h-7 bg-quant-gold rounded-md flex items-center justify-center text-white text-sm font-black shrink-0">
            小
          </span>
          {!sidebarCollapsed && <span className="truncate">小天量化</span>}
        </Link>
      </div>

      {/* Nav */}
      <nav className="flex-1 overflow-y-auto py-3 px-2 space-y-1">
        {navItems.map((item) => {
          const active = location.pathname === item.path
          return (
            <Link
              key={item.path}
              to={item.path}
              className={cn(
                'flex items-center gap-3 px-3 py-2.5 rounded-md text-sm font-medium transition-colors',
                active
                  ? 'bg-quant-gold/10 text-quant-gold'
                  : 'text-muted-foreground hover:text-foreground hover:bg-white/5'
              )}
              title={sidebarCollapsed ? item.label : undefined}
            >
              <item.icon className="w-[18px] h-[18px] shrink-0" />
              {!sidebarCollapsed && <span>{item.label}</span>}
            </Link>
          )
        })}
      </nav>

      {/* Bottom: Settings + Collapse */}
      <div className="p-2 border-t border-quant-border space-y-1">
        <Link
          to="/settings"
          className={cn(
            'flex items-center gap-3 px-3 py-2.5 rounded-md text-sm font-medium transition-colors',
            location.pathname === '/settings'
              ? 'bg-quant-gold/10 text-quant-gold'
              : 'text-muted-foreground hover:text-foreground hover:bg-white/5'
          )}
          title={sidebarCollapsed ? '设置' : undefined}
        >
          <Settings className="w-[18px] h-[18px] shrink-0" />
          {!sidebarCollapsed && <span>设置</span>}
        </Link>

        <button
          onClick={toggleSidebar}
          className="w-full flex items-center gap-3 px-3 py-2.5 rounded-md text-sm text-muted-foreground hover:text-foreground hover:bg-white/5 transition-colors"
          title={sidebarCollapsed ? '展开' : '收起'}
        >
          {sidebarCollapsed ? (
            <ChevronRight className="w-[18px] h-[18px] shrink-0" />
          ) : (
            <>
              <ChevronLeft className="w-[18px] h-[18px] shrink-0" />
              <span>收起侧边栏</span>
            </>
          )}
        </button>
      </div>
    </aside>
  )
}
