type FieldType = "text" | "password" | "number" | "switch" | "select";

interface SettingField {
  key: string;
  label: string;
  type: FieldType;
  placeholder?: string;
  options?: string[];
  defaultValue?: string | number | boolean;
  description?: string;
}

interface SettingGroup {
  key: string;
  label: string;
  icon: React.ElementType;
  description: string;
  fields: SettingField[];
}

