function RestartBanner({ onCopy }: { onCopy: () => void }) {
  const [copied, setCopied] = useState(false);

  const handleCopy = () => {
    onCopy();
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="mb-6 flex items-center gap-3 rounded-lg border border-amber-500/20 bg-amber-500/10 px-4 py-3">
      <AlertTriangle className="h-5 w-5 shrink-0 text-amber-400" />
      <div className="flex-1 text-sm text-amber-200">
        配置已修改，需要重启服务才能生效。请复制下方命令并在终端执行：
        <code className="ml-2 rounded bg-amber-500/20 px-1.5 py-0.5 text-xs font-mono text-amber-300">
          docker compose restart app
        </code>
      </div>
      <button
        onClick={handleCopy}
        className="flex items-center gap-1.5 rounded-md bg-amber-500/20 px-3 py-1.5 text-xs font-medium text-amber-300 transition-colors hover:bg-amber-500/30"
      >
        {copied ? (
          <Check className="h-3.5 w-3.5" />
        ) : (
          <Copy className="h-3.5 w-3.5" />
        )}
        {copied ? "已复制" : "复制命令"}
      </button>
    </div>
  );
}

function ToggleField({
  value,
  onChange,
}: {
  value: boolean;
  onChange: (v: boolean) => void;
}) {
  return (
    <button
      onClick={() => onChange(!value)}
      className={cn(
        "relative h-5 w-10 rounded-full transition-colors",
        value ? "bg-[#d4a574]" : "bg-[#1c1c1c]"
      )}
      aria-checked={value}
      role="switch"
    >
      <span
        className={cn(
          "absolute top-0.5 h-4 w-4 rounded-full bg-white transition-transform",
          value ? "left-5" : "left-0.5"
        )}
      />
    </button>
  );
}

function PasswordInput({
  value,
  onChange,
  placeholder,
}: {
  value: string;
  onChange: (v: string) => void;
  placeholder?: string;
}) {
  const [visible, setVisible] = useState(false);

  return (
    <div className="relative">
      <input
        type={visible ? "text" : "password"}
        value={value}
        onChange={(e) => onChange(e.target.value)}
        placeholder={placeholder}
        className="w-full rounded-md border border-[#1c1c1c] bg-[#0a0a0a] px-3 py-2 pr-10 text-sm text-white placeholder-[#444444] outline-none transition-colors focus:border-[#d4a574]"
      />
      <button
        type="button"
        onClick={() => setVisible(!visible)}
        className="absolute right-2.5 top-1/2 -translate-y-1/2 text-[#555555] hover:text-[#888888]"
      >
        {visible ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
      </button>
    </div>
  );
}

function TextInput({
  value,
  onChange,
  placeholder,
  type = "text",
}: {
  value: string;
  onChange: (v: string) => void;
  placeholder?: string;
  type?: "text" | "number";
}) {
  return (
    <input
      type={type}
      value={value}
      onChange={(e) => onChange(e.target.value)}
      placeholder={placeholder}
      className="w-full rounded-md border border-[#1c1c1c] bg-[#0a0a0a] px-3 py-2 text-sm text-white placeholder-[#444444] outline-none transition-colors focus:border-[#d4a574]"
    />
  );
}

function SelectField({
  value,
  onChange,
  options,
}: {
  value: string;
  onChange: (v: string) => void;
  options: string[];
}) {
  return (
    <div className="relative">
      <select
        value={value}
        onChange={(e) => onChange(e.target.value)}
        className="w-full appearance-none rounded-md border border-[#1c1c1c] bg-[#0a0a0a] px-3 py-2 pr-8 text-sm text-white outline-none transition-colors focus:border-[#d4a574]"
      >
        {options.map((opt) => (
          <option key={opt} value={opt}>
            {opt}
          </option>
        ))}
      </select>
      <ChevronRight className="pointer-events-none absolute right-2.5 top-1/2 h-4 w-4 -translate-y-1/2 rotate-90 text-[#555555]" />
    </div>
  );
}

function SettingFieldRow({
  field,
  value,
  onChange,
}: {
  field: SettingField;
  value: string | number | boolean;
  onChange: (v: string | number | boolean) => void;
}) {
  return (
    <div className="space-y-1.5">
      <div className="flex items-center justify-between">
        <label className="text-xs font-medium text-[#aaaaaa]">
          {field.label}
        </label>
        {field.type === "switch" && (
          <ToggleField
            value={!!value}
            onChange={(v) => onChange(v)}
          />
        )}
      </div>

      {field.type !== "switch" && (
        <>
          {field.type === "password" && (
            <PasswordInput
              value={String(value ?? "")}
              onChange={(v) => onChange(v)}
              placeholder={field.placeholder}
            />
          )}
          {field.type === "text" && (
            <TextInput
              value={String(value ?? "")}
              onChange={(v) => onChange(v)}
              placeholder={field.placeholder}
            />
          )}
          {field.type === "number" && (
            <TextInput
              type="number"
              value={String(value ?? "")}
              onChange={(v) => onChange(v === "" ? "" : Number(v))}
              placeholder={field.placeholder}
            />
          )}
          {field.type === "select" && field.options && (
            <SelectField
              value={String(value ?? "")}
              onChange={(v) => onChange(v)}
              options={field.options}
            />
          )}
        </>
      )}

      {field.description && (
        <p className="text-[11px] text-[#555555]">{field.description}</p>
      )}
    </div>
  );
}

function ExchangeTestButtons() {
  const [status, setStatus] = useState<Record<string, boolean | null>>({
    Binance: null,
    OKX: null,
  });

  const test = (name: string) => {
    setStatus((s) => ({ ...s, [name]: null }));
    setTimeout(() => {
      setStatus((s) => ({ ...s, [name]: Math.random() > 0.2 }));
    }, 1200);
  };

  return (
    <div className="mt-4 grid grid-cols-2 gap-3">
      {["Binance", "OKX"].map((name) => (
        <button
          key={name}
          onClick={() => test(name)}
          className="flex items-center justify-center gap-2 rounded-md border border-[#1c1c1c] bg-[#0a0a0a] px-3 py-2 text-xs font-medium text-[#aaaaaa] transition-colors hover:border-[#d4a574]/30 hover:text-white"
        >
          {status[name] === null ? (
            <Wifi className="h-3.5 w-3.5" />
          ) : status[name] ? (
            <Wifi className="h-3.5 w-3.5 text-emerald-400" />
          ) : (
            <WifiOff className="h-3.5 w-3.5 text-red-400" />
          )}
          测试 {name} 连接
        </button>
      ))}
    </div>
  );
}

function OpenRouterBalanceCard() {
  const [balance, setBalance] = useState<number | null>(null);
  const [loading, setLoading] = useState(false);

  const query = () => {
    setLoading(true);
    setTimeout(() => {
      setBalance(12.3456);
      setLoading(false);
    }, 1000);
  };

  return (
    <div className="mt-4 rounded-lg border border-[#1c1c1c] bg-[#0a0a0a] p-4">
      <div className="flex items-center justify-between">
        <div>
          <div className="text-xs font-medium text-[#aaaaaa]">OpenRouter 余额</div>
          <div className="mt-1 text-lg font-semibold text-white">
            {balance !== null ? `$${balance.toFixed(4)}` : "--"}
          </div>
        </div>
        <button
          onClick={query}
          disabled={loading}
          className="flex items-center gap-1.5 rounded-md bg-[#d4a574]/10 px-3 py-1.5 text-xs font-medium text-[#d4a574] transition-colors hover:bg-[#d4a574]/20 disabled:opacity-50"
        >
          <RotateCcw className={cn("h-3.5 w-3.5", loading && "animate-spin")} />
          {loading ? "查询中..." : "查询余额"}
        </button>
      </div>
    </div>
  );
}

