/*  Main Component                                                     */
/* ------------------------------------------------------------------ */

export function Settings() {
  const [activeGroup, setActiveGroup] = useState("exchange");
  const [search, setSearch] = useState("");
  const [dirty, setDirty] = useState(false);
  const [values, setValues] = useState<Record<string, string | number | boolean>>(
    () => {
      const init: Record<string, string | number | boolean> = {};
      GROUPS.forEach((g) =>
        g.fields.forEach((f) => {
          if (f.defaultValue !== undefined) init[f.key] = f.defaultValue;
        })
      );
      return init;
    }
  );

  const updateValue = useCallback(
    (key: string, val: string | number | boolean) => {
      setValues((prev) => ({ ...prev, [key]: val }));
      setDirty(true);
    },
    []
  );

  const handleReset = () => {
    const init: Record<string, string | number | boolean> = {};
    GROUPS.forEach((g) =>
      g.fields.forEach((f) => {
        if (f.defaultValue !== undefined) init[f.key] = f.defaultValue;
      })
    );
    setValues(init);
    setDirty(false);
  };

  const handleSave = () => {
    setDirty(false);
  };

  const handleCopyCommand = () => {
    navigator.clipboard.writeText("docker compose restart app");
  };

  /* ---------------- Search flattening ---------------- */
  const filteredFields = useMemo(() => {
    if (!search.trim()) return null;
    const q = search.toLowerCase();
    const out: { group: SettingGroup; field: SettingField }[] = [];
    GROUPS.forEach((g) =>
      g.fields.forEach((f) => {
        if (
          f.label.toLowerCase().includes(q) ||
          f.key.toLowerCase().includes(q) ||
          g.label.toLowerCase().includes(q)
        ) {
          out.push({ group: g, field: f });
        }
      })
    );
    return out;
  }, [search]);

  const activeGroupData = GROUPS.find((g) => g.key === activeGroup)!;

  return (
    <div className="h-full overflow-y-auto bg-[#0a0a0a]">
      <div className="mx-auto max-w-6xl p-6">
        {/* Restart Alert */}
        {dirty && <RestartBanner onCopy={handleCopyCommand} />}

        {/* Page Header */}
        <PageHeader
          title="系统设置"
          subtitle="管理交易所、API 密钥、通知、外观、数据、安全及 AI 模型配置"
          actions={
            <div className="flex items-center gap-2">
              <button
                onClick={handleReset}
                className="flex items-center gap-1.5 rounded-md border border-[#1c1c1c] bg-[#111111] px-3 py-1.5 text-xs font-medium text-[#aaaaaa] transition-colors hover:border-[#444444] hover:text-white"
              >
                <RotateCcw className="h-3.5 w-3.5" />
                重置
              </button>
              <button
                onClick={handleSave}
                className="flex items-center gap-1.5 rounded-md bg-[#d4a574] px-3 py-1.5 text-xs font-medium text-black transition-opacity hover:opacity-90"
              >
                <Save className="h-3.5 w-3.5" />
                保存
              </button>
            </div>
          }
        />

        <div className="mt-6 flex gap-6">
          {/* Left Nav */}
          <div className="w-56 shrink-0 space-y-4">
            {/* Search */}
            <div className="relative">
              <Search className="absolute left-2.5 top-1/2 h-4 w-4 -translate-y-1/2 text-[#444444]" />
              <input
                type="text"
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                placeholder="搜索设置..."
                className="w-full rounded-md border border-[#1c1c1c] bg-[#111111] py-2 pl-9 pr-3 text-sm text-white placeholder-[#444444] outline-none transition-colors focus:border-[#d4a574]"
              />
            </div>

            {/* Menu */}
            <nav className="space-y-1">
              {GROUPS.map((g) => (
                <button
                  key={g.key}
                  onClick={() => {
                    setActiveGroup(g.key);
                    setSearch("");
                  }}
                  className={cn(
                    "flex w-full items-center gap-3 rounded-md px-3 py-2.5 text-left text-sm transition-colors",
                    activeGroup === g.key && !search
                      ? "bg-[#d4a574]/10 text-[#d4a574]"
                      : "text-[#888888] hover:bg-[#111111] hover:text-white"
                  )}
                >
                  <g.icon className="h-4 w-4 shrink-0" />
                  <span className="flex-1">{g.label}</span>
                </button>
              ))}
            </nav>
          </div>

          {/* Right Detail */}
          <div className="flex-1 space-y-4">
            {search && filteredFields ? (
              /* ---- Search mode ---- */
              <SectionCard
                title={`搜索结果 (${filteredFields.length})`}
                bodyClassName="space-y-5"
              >
                {filteredFields.length === 0 ? (
                  <div className="py-8 text-center text-sm text-[#555555]">
                    未找到与 “{search}” 相关的设置
                  </div>
                ) : (
                  filteredFields.map(({ group, field }) => (
                    <div key={field.key} className="space-y-2">
                      <div className="flex items-center gap-2">
                        <span className="rounded bg-[#1c1c1c] px-1.5 py-0.5 text-[10px] font-medium text-[#666666]">
                          {group.label}
                        </span>
                      </div>
                      <SettingFieldRow
                        field={field}
                        value={values[field.key] ?? ""}
                        onChange={(v) => updateValue(field.key, v)}
                      />
                    </div>
                  ))
                )}
              </SectionCard>
            ) : (
              /* ---- Normal group mode ---- */
              <>
                <SectionCard
                  title={
                    <div className="flex items-center gap-2">
                      <activeGroupData.icon className="h-4 w-4 text-[#d4a574]" />
                      {activeGroupData.label}
                    </div>
                  }
                  bodyClassName="space-y-5"
                >
                  <p className="text-xs text-[#555555]">
                    {activeGroupData.description}
                  </p>

                  {activeGroupData.fields.map((field) => (
                    <SettingFieldRow
                      key={field.key}
                      field={field}
                      value={values[field.key] ?? ""}
                      onChange={(v) => updateValue(field.key, v)}
                    />
                  ))}

                  {/* Special cards */}
                  {activeGroup === "api" && <ExchangeTestButtons />}
                  {activeGroup === "ai" && <OpenRouterBalanceCard />}
                </SectionCard>

                {/* Bottom actions */}
                <div className="flex items-center justify-end gap-2 pt-2">
                  <button
                    onClick={handleReset}
                    className="flex items-center gap-1.5 rounded-md border border-[#1c1c1c] bg-[#111111] px-4 py-2 text-xs font-medium text-[#aaaaaa] transition-colors hover:border-[#444444] hover:text-white"
                  >
                    <RotateCcw className="h-3.5 w-3.5" />
                    重置
                  </button>
                  <button
                    onClick={handleSave}
                    className="flex items-center gap-1.5 rounded-md bg-[#d4a574] px-4 py-2 text-xs font-medium text-black transition-opacity hover:opacity-90"
                  >
                    <Save className="h-3.5 w-3.5" />
                    保存
                  </button>
                </div>
              </>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}
